import java.io.IOException;
import java.io.PrintStream;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private final PrintStream originalOut = System.out;
    private TestPrintStream testOut;

    @BeforeEach
    void setUp() {
        testOut = new TestPrintStream();
        System.setOut(testOut);
    }

    @AfterEach
    void tearDown() {
        System.setOut(originalOut);
    }

    @Test
    void testPrinter_DefaultCSVFormat_PrinterNotNull() throws IOException {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVPrinter printer = format.printer();
        assertNotNull(printer);
        // The printer should write to System.out, which is now testOut
        printer.print("test");
        printer.flush();
        assertTrue(testOut.getContent().contains("test"));
        printer.close();
    }

    @Test
    void testPrinter_ExcelCSVFormat_PrinterNotNull() throws IOException {
        CSVFormat format = CSVFormat.EXCEL;
        CSVPrinter printer = format.printer();
        assertNotNull(printer);
        printer.print("excel");
        printer.flush();
        assertTrue(testOut.getContent().contains("excel"));
        printer.close();
    }

    @Test
    void testPrinter_CustomCSVFormat_PrinterNotNull() throws IOException {
        CSVFormat format = CSVFormat.DEFAULT.withDelimiter(';').withQuote('\'');
        CSVPrinter printer = format.printer();
        assertNotNull(printer);
        printer.print("custom");
        printer.flush();
        assertTrue(testOut.getContent().contains("custom"));
        printer.close();
    }

    // Helper class to capture System.out output
    private static class TestPrintStream extends PrintStream {
        private final StringBuilder sb = new StringBuilder();

        TestPrintStream() {
            super(System.out);
        }

        @Override
        public void print(String s) {
            sb.append(s);
        }

        @Override
        public void println(String s) {
            sb.append(s).append(System.lineSeparator());
        }

        @Override
        public void write(byte[] buf, int off, int len) {
            sb.append(new String(buf, off, len));
        }

        String getContent() {
            return sb.toString();
        }
    }
}
